func TestE2E_MockSmokeAllProxies(t *testing.T) {
	mock := testutil.NewMockBinder()
	var totalMethods, passedMethods, panickedMethods int

	for _, entry := range allMockProxies {
		t.Run(entry.name, func(t *testing.T) {
			proxy := entry.constructor(mock)
			result := testutil.SmokeTestAllMethods(t, proxy)
			totalMethods += result.Total
			passedMethods += result.Passed
			panickedMethods += result.Panicked
		})
	}

	t.Logf("TOTAL: %d proxy types, %d methods exercised, %d passed, %d panicked",
		len(allMockProxies), totalMethods, passedMethods, panickedMethods)
}
